    pretty = json.dumps(rep, indent=2, ensure_ascii=False, sort_keys=True)
    await send_long_message(update, f"🧪 Optimize Report (last)\n{HDR}\n```\n{pretty}\n```", parse_mode=ParseMode.MARKDOWN)








